</template>

<script setup lang="ts">
definePageMeta({ layout: 'auth' })
const toast = useToast(); const route = useRoute(); const step = ref(1); const totalSteps = 7; const hierarchyStep = -1; const programStep = 3; const feeStep = 4; const staffStep = 5; const ownerStep = 6; const loading = ref(false); const logoFile = ref<File | null>(null)
const initialPlan = ['city-starter', 'city-pro', 'state-pro', 'national'].includes(String(route.query.trialPlan)) ? String(route.query.trialPlan) : 'free'
const form = reactive({ organizationName: '', workspaceSlug: '', dojoName: '', dojoAddress: '', dojoCity: '', dojoStateProvince: '', dojoCountry: '', dojoPhone: '', dojoEmail: '', districtName: '', branchName: '', feeName: 'Monthly tuition', feeAmount: null as number | null, name: '', email: '', password: '', martialArt: '', style: '', customMartialArt: '', customStyle: '', subscriptionPlan: initialPlan })
const planOptions = [
  { label: 'Free Forever — one owner, one dojo, up to 25 students', value: 'free' },
  { label: 'City Starter — two dojos in one city, staff, 75 students per dojo', value: 'city-starter' },
