]
const trialPlan = computed(() => form.subscriptionPlan === 'free' ? null : form.subscriptionPlan); const billingPeriod = computed(() => route.query.billingPeriod === 'monthly' ? 'monthly' : 'annual')
const isAdvancedPlan = computed(() => ['state-pro', 'national'].includes(form.subscriptionPlan))
const hierarchyPreview = computed(() => { const district = form.districtName.trim() ? ` → ${form.districtName.trim()}` : ''; const branch = form.branchName.trim() || form.dojoName.trim() || 'Your dojo'; return form.subscriptionPlan === 'national' ? `${form.dojoCountry || 'Country'} → ${form.dojoStateProvince || 'State'}${district} → ${form.dojoCity || 'City'} → ${branch}` : `${form.dojoStateProvince || 'State'}${district} → ${form.dojoCity || 'City'} → ${branch}` })
const martialArtOptions = [
  { label: 'Aikido', value: 'aikido' }, { label: 'Brazilian Jiu-Jitsu', value: 'bjj' }, { label: 'Boxing', value: 'boxing' }, { label: 'Capoeira', value: 'capoeira' },
  { label: 'Eskrima / Arnis / Kali', value: 'eskrima' }, { label: 'Hapkido', value: 'hapkido' }, { label: 'Iaido', value: 'iaido' }, { label: 'Jeet Kune Do', value: 'jkd' },
