  { label: 'Kenjutsu', value: 'kenjutsu' }, { label: 'Kendo', value: 'kendo' }, { label: 'Kickboxing', value: 'kickboxing' }, { label: 'Krav Maga', value: 'krav_maga' },
  { label: 'Kung Fu / Wushu', value: 'kung_fu' }, { label: 'Mixed Martial Arts (MMA)', value: 'mma' }, { label: 'Muay Thai', value: 'muay_thai' }, { label: 'Pencak Silat', value: 'silat' },
  { label: 'Sambo', value: 'sambo' }, { label: 'Savate', value: 'savate' }, { label: 'Sumo', value: 'sumo' }, { label: 'Taekwondo', value: 'taekwondo' },
  { label: 'Tai Chi / Taijiquan', value: 'tai_chi' }, { label: 'Tang Soo Do', value: 'tang_soo_do' }, { label: 'Wrestling', value: 'wrestling' }, { label: 'Wing Chun', value: 'wing_chun' },
  { label: 'Other martial art', value: 'custom' },
]
const stylesByMartialArt: Record<string, Array<{ label: string, value: string }>> = {
  aikido: [{ label: 'Aikikai', value: 'aikikai' }, { label: 'Iwama-ryu', value: 'iwama_ryu' }, { label: 'Ki Aikido (Shin Shin Toitsu)', value: 'ki_aikido' }, { label: 'Yoshinkan', value: 'yoshinkan' }],
  bjj: [{ label: 'Brazilian Jiu-Jitsu', value: 'brazilian_jiu_jitsu' }, { label: 'Gracie Jiu-Jitsu', value: 'gracie_jiu_jitsu' }, { label: '10th Planet Jiu-Jitsu', value: '10th_planet' }],
  boxing: [{ label: 'Western boxing', value: 'western_boxing' }, { label: 'Bare-knuckle boxing', value: 'bare_knuckle' }],
  capoeira: [{ label: 'Angola', value: 'angola' }, { label: 'Regional', value: 'regional' }, { label: 'Contemporânea', value: 'contemporanea' }],
  eskrima: [{ label: 'Arnis', value: 'arnis' }, { label: 'Balintawak', value: 'balintawak' }, { label: 'Doce Pares', value: 'doce_pares' }, { label: 'Kali', value: 'kali' }, { label: 'Modern Arnis', value: 'modern_arnis' }, { label: 'Pekiti-Tirsia', value: 'pekiti_tirsia' }, { label: 'Sayoc Kali', value: 'sayoc_kali' }],
  hapkido: [{ label: 'Traditional Hapkido', value: 'traditional_hapkido' }, { label: 'Combat Hapkido', value: 'combat_hapkido' }, { label: 'Kuk Sool Won', value: 'kuk_sool_won' }],
  iaido: [{ label: 'Muso Jikiden Eishin-ryu', value: 'muso_jikiden_eishin_ryu' }, { label: 'Muso Shinden-ryu', value: 'muso_shinden_ryu' }, { label: 'Seitei Iaido', value: 'seitei_iaido' }],
  jkd: [{ label: 'Jun Fan Jeet Kune Do', value: 'jun_fan' }, { label: 'Jeet Kune Do Concepts', value: 'jkd_concepts' }],
  judo: [{ label: 'Kodokan Judo', value: 'kodokan' }, { label: 'Kosen Judo', value: 'kosen' }],
  jujutsu: [{ label: 'Daito-ryu', value: 'daito_ryu' }, { label: 'Hakko-ryu', value: 'hakko_ryu' }, { label: 'Shorinji Kempo', value: 'shorinji_kempo' }, { label: 'Traditional Jujutsu', value: 'traditional_jujutsu' }],
  kalaripayattu: [{ label: 'Northern Kalari', value: 'northern_kalari' }, { label: 'Southern Kalari', value: 'southern_kalari' }],
  karate: [{ label: 'Goju-ryu', value: 'goju_ryu' }, { label: 'Kyokushin', value: 'kyokushin' }, { label: 'Shito-ryu', value: 'shito_ryu' }, { label: 'Shorin-ryu', value: 'shorin_ryu' }, { label: 'Shotokan', value: 'shotokan' }, { label: 'Uechi-ryu', value: 'uechi_ryu' }, { label: 'Wado-ryu', value: 'wado_ryu' }, { label: 'Isshin-ryu', value: 'isshin_ryu' }, { label: 'American Kenpo', value: 'american_kenpo' }],
  kenjutsu: [{ label: 'Kashima Shin-ryu', value: 'kashima_shin_ryu' }, { label: 'Katori Shinto-ryu', value: 'katori_shinto_ryu' }, { label: 'Niten Ichi-ryu', value: 'niten_ichi_ryu' }],
  kendo: [{ label: 'All Japan Kendo Federation', value: 'ajkf_kendo' }, { label: 'Sport Kendo', value: 'sport_kendo' }],
  kickboxing: [{ label: 'American Kickboxing', value: 'american_kickboxing' }, { label: 'Dutch Kickboxing', value: 'dutch_kickboxing' }, { label: 'Japanese Kickboxing', value: 'japanese_kickboxing' }, { label: 'K-1 Rules', value: 'k1_rules' }],
  krav_maga: [{ label: 'Civilian Krav Maga', value: 'civilian_krav_maga' }, { label: 'IKMF', value: 'ikmf' }, { label: 'KMG', value: 'kmg' }],
