  mma: [{ label: 'Mixed Martial Arts', value: 'mixed_martial_arts' }, { label: 'Combat Sambo MMA', value: 'combat_sambo_mma' }],
  muay_thai: [{ label: 'Muay Boran', value: 'muay_boran' }, { label: 'Muay Chaiya', value: 'muay_chaiya' }, { label: 'Muay Thai', value: 'muay_thai' }],
