  sambo: [{ label: 'Combat Sambo', value: 'combat_sambo' }, { label: 'Sport Sambo', value: 'sport_sambo' }],
  savate: [{ label: 'Assaut', value: 'assaut' }, { label: 'Combat Savate', value: 'combat_savate' }, { label: 'Savate Défense', value: 'savate_defense' }],
  sumo: [{ label: 'Amateur Sumo', value: 'amateur_sumo' }, { label: 'Professional Sumo', value: 'professional_sumo' }],
  taekwondo: [{ label: 'Chang Hon (ITF)', value: 'chang_hon_itf' }, { label: 'Kukkiwon / WT', value: 'kukkiwon_wt' }, { label: 'Songahm (ATA)', value: 'songahm_ata' }, { label: 'Tang Soo Do', value: 'tang_soo_do' }],
  tai_chi: [{ label: 'Chen style', value: 'chen' }, { label: 'Sun style', value: 'sun' }, { label: 'Wu style', value: 'wu' }, { label: 'Yang style', value: 'yang' }],
  tang_soo_do: [{ label: 'Moo Duk Kwan', value: 'moo_duk_kwan' }, { label: 'World Tang Soo Do', value: 'world_tang_soo_do' }],
  wrestling: [{ label: 'Freestyle wrestling', value: 'freestyle' }, { label: 'Greco-Roman wrestling', value: 'greco_roman' }, { label: 'Folkstyle wrestling', value: 'folkstyle' }, { label: 'Catch wrestling', value: 'catch_wrestling' }],
  wing_chun: [{ label: 'Ip Man lineage', value: 'ip_man' }, { label: 'Leung Ting', value: 'leung_ting' }, { label: 'Traditional Wing Chun', value: 'traditional_wing_chun' }],
}
const customStyleOption = { label: 'Other / custom style', value: 'custom' }
const styleOptions = computed(() => [...(stylesByMartialArt[form.martialArt] || []), customStyleOption])
const martialArtLabel = computed(() => form.martialArt === 'custom' ? (form.customMartialArt.trim() || 'martial art') : martialArtOptions.find(item => item.value === form.martialArt)?.label || 'martial art')
const staffMembers = ref<Array<{ name: string, email: string, password: string, assignmentRole: 'instructor' | 'dojo_head' }>>([]); const staffRoleOptions = [{ label: 'Instructor', value: 'instructor' }, { label: 'Dojo manager', value: 'dojo_head' }]
watch(() => form.martialArt, () => { form.style = ''; form.customStyle = '' })
function onFileChange(event: Event) { logoFile.value = (event.target as HTMLInputElement).files?.[0] || null }
function addStaff() { staffMembers.value.push({ name: '', email: '', password: '', assignmentRole: 'instructor' }) }; function removeStaff(index: number) { staffMembers.value.splice(index, 1) }
function validStep() { if (step.value === 1 && (!form.organizationName.trim() || !form.workspaceSlug.trim())) return 'Enter your organization name and workspace address.'; if (step.value === 2 && (!form.dojoName.trim() || !form.dojoAddress.trim() || !form.dojoCity.trim() || !form.dojoStateProvince.trim() || !form.dojoCountry.trim())) return 'Enter your dojo name and complete address.'; if (step.value === 3 && !form.martialArt) return 'Select the martial art you teach.'; if (step.value === 3 && form.martialArt === 'custom' && !form.customMartialArt.trim()) return 'Enter your martial art.'; if (step.value === 3 && !form.style) return 'Select your style or school.'; if (step.value === 3 && form.style === 'custom' && !form.customStyle.trim()) return 'Enter your style or lineage.'; if (step.value === 4 && (!form.feeName.trim() || !form.feeAmount || form.feeAmount < 1)) return 'Enter a fee plan name and amount.'; if (step.value === 5 && trialPlan.value && staffMembers.value.some(staff => !staff.name.trim() || !/^\S+@\S+\.\S+$/.test(staff.email) || staff.password.length < 8)) return 'Each staff member needs a name, valid email, and temporary password of at least 8 characters.'; if (step.value === 6) { if (!form.name.trim()) return 'Enter your name.'; if (!/^\S+@\S+\.\S+$/.test(form.email)) return 'Enter a valid email address.'; if (form.password.length < 8) return 'Choose a password with at least 8 characters.' }; return null }
async function next() { const message = validStep(); if (message) { toast.add({ color: 'warning', title: message }); return }; if (step.value < totalSteps) { step.value++; return }; loading.value = true; try { const fd = new FormData(); for (const [key, value] of Object.entries(form)) fd.append(key, String(value ?? '')); fd.set('martialArt', form.martialArt === 'custom' ? form.customMartialArt.trim() : form.martialArt); fd.set('style', form.style === 'custom' ? form.customStyle.trim() : form.style); fd.append('staff', JSON.stringify(staffMembers.value)); if (trialPlan.value) { fd.append('trialPlan', trialPlan.value); fd.append('billingPeriod', billingPeriod.value) }; if (logoFile.value) fd.append('logo', logoFile.value); const response = await $fetch<any>('/api/onboarding', { method: 'POST', body: fd }); if (response.workspaceUrl) { window.location.assign(`${response.workspaceUrl}/auth/login?created=1&email=${encodeURIComponent(form.email)}`); return }; await navigateTo({ path: '/auth/login', query: { created: '1', email: form.email } }) } catch (error: any) { toast.add({ color: 'error', title: 'We could not create your workspace', description: error.data?.statusMessage || error.message }) } finally { loading.value = false } }
